"""Strategy seam: where does a new subscription start reading?

This is the Open/Closed pay-off. The broker depends on the interface; adding a
new policy (e.g. 'start from timestamp T') is a new class, zero core changes.
"""
from __future__ import annotations

from abc import ABC, abstractmethod

from models import Topic, StartPosition


# ── WHY THIS INTERFACE ───────────────────────────────────────────────────────
# The broker never hardcodes the start offset. It asks a strategy. This keeps
# subscribe() free of policy if/else.
class SubscriptionStartStrategy(ABC):
    @abstractmethod
    def initial_offset(self, topic: Topic) -> int:
        """Return the offset a new subscription should begin at for `topic`."""
        raise NotImplementedError


class EarliestStrategy(SubscriptionStartStrategy):
    # WHY: 0 means "read the whole history" — full replay from the beginning.
    def initial_offset(self, topic: Topic) -> int:
        return 0


class LatestStrategy(SubscriptionStartStrategy):
    # WHY: current size means "only messages published from now on" — the spec's
    #      default ("receive every message published AFTER they subscribe").
    def initial_offset(self, topic: Topic) -> int:
        return topic.size()


# ── WHY THIS FUNCTION ────────────────────────────────────────────────────────
# Factory: turns the StartPosition enum coming from the public API into a real
# strategy object, so the broker stays decoupled from concrete classes.
def strategy_for(position: StartPosition) -> SubscriptionStartStrategy:
    if position == StartPosition.EARLIEST:
        return EarliestStrategy()
    return LatestStrategy()
